INSERT INTO public.vocab (level_id, word, hiragana, romaji, meaning, part_of_speech, usage_id, usage_jp, full_meaning, example_sentence, example_hiragana, example_meaning, order_index) VALUES
(1, 'こんにちは', 'こんにちは', 'konnichiwa', 'halo / selamat siang', 'Ungkapan', 'Sapaan saat siang hari (antara jam 10 pagi sampai sore)', '昼の挨拶', 'Salam universal yang dipakai sebagai sapaan umum di siang hari kepada siapa saja, formal maupun informal.', 'こんにちは、田中さん。', 'こんにちは、たなかさん。', 'Selamat siang, Tanaka-san.', 1),
(1, 'おはよう', 'おはよう', 'ohayō', 'selamat pagi', 'Ungkapan', 'Sapaan pagi hari (informal). Versi sopan: おはようございます', '朝の挨拶', 'Salam pagi hari, biasanya dipakai sampai jam 10 pagi. Versi おはようございます lebih sopan.', 'おはよう、お母さん。', 'おはよう、おかあさん。', 'Selamat pagi, Ibu.', 2),
(1, 'こんばんは', 'こんばんは', 'konbanwa', 'selamat malam', 'Ungkapan', 'Sapaan malam hari (setelah matahari terbenam)', '夜の挨拶', 'Salam saat bertemu seseorang di malam hari. Bukan untuk perpisahan — gunakan おやすみ untuk itu.', 'こんばんは、皆さん。', 'こんばんは、みなさん。', 'Selamat malam, semuanya.', 3),
(1, 'ありがとう', 'ありがとう', 'arigatō', 'terima kasih', 'Ungkapan', 'Ucapan terima kasih (informal). Versi sopan: ありがとうございます', '感謝の言葉', 'Ungkapan rasa terima kasih. Tambahkan ございます untuk konteks formal atau kepada orang yang lebih tua.', 'ありがとう、友達。', 'ありがとう、ともだち。', 'Terima kasih, teman.', 4),
(1, 'すみません', 'すみません', 'sumimasen', 'maaf / permisi', 'Ungkapan', 'Bisa berarti minta maaf atau memanggil perhatian seseorang', 'すみませんは謝罪または呼びかけ', 'Ungkapan multi-fungsi: minta maaf, permisi, atau memanggil pelayan/penjual.', 'すみません、トイレはどこですか。', 'すみません、トイレはどこですか。', 'Permisi, toilet di mana?', 5),
(1, 'はい', 'はい', 'hai', 'ya', 'Ungkapan', 'Jawaban persetujuan atau konfirmasi', '肯定の返事', 'Cara mengiyakan atau merespon panggilan. Lebih sopan daripada うん.', 'はい、わかりました。', 'はい、わかりました。', 'Ya, saya mengerti.', 6),
(1, 'いいえ', 'いいえ', 'iie', 'tidak', 'Ungkapan', 'Jawaban negatif atau penolakan', '否定の返事', 'Cara menyangkal atau menolak. Versi informal: いや atau ううん.', 'いいえ、違います。', 'いいえ、ちがいます。', 'Tidak, salah.', 7),
(1, 'さようなら', 'さようなら', 'sayōnara', 'selamat tinggal', 'Ungkapan', 'Salam perpisahan untuk jangka waktu lama', '別れの挨拶', 'Salam pisah formal. Untuk pisah sebentar, gunakan じゃあね atau また.', 'さようなら、また会いましょう。', 'さようなら、またあいましょう。', 'Selamat tinggal, sampai jumpa lagi.', 8),
(1, 'おやすみ', 'おやすみ', 'oyasumi', 'selamat tidur', 'Ungkapan', 'Salam sebelum tidur atau berpisah di malam hari', '寝る前の挨拶', 'Diucapkan sebelum tidur atau saat berpisah di malam hari. Versi sopan: おやすみなさい.', 'おやすみ、また明日。', 'おやすみ、またあした。', 'Selamat tidur, sampai besok.', 9),
(1, 'いただきます', 'いただきます', 'itadakimasu', 'selamat makan', 'Ungkapan', 'Diucapkan sebelum mulai makan', '食事の前に言う', 'Ungkapan rasa syukur sebelum makan, secara literal berarti "saya menerima".', 'いただきます、おいしそう。', 'いただきます、おいしそう。', 'Selamat makan, kelihatan enak.', 10),
(1, '私', 'わたし', 'watashi', 'saya', 'Kata ganti', 'Kata ganti orang pertama (netral, sopan)', '一人称の代名詞', 'Kata ganti "saya" yang netral untuk pria dan wanita, cocok untuk situasi formal maupun informal.', '私は学生です。', 'わたしはがくせいです。', 'Saya adalah pelajar.', 11),
(1, 'あなた', 'あなた', 'anata', 'kamu / anda', 'Kata ganti', 'Kata ganti orang kedua. Jarang dipakai langsung — pakai nama orangnya.', '二人称の代名詞', 'Lebih sering panggil nama orang daripada pakai あなた karena bisa terkesan terlalu langsung.', 'あなたの名前は何ですか。', 'あなたのなまえはなんですか。', 'Siapa nama Anda?', 12),
(1, '彼', 'かれ', 'kare', 'dia (laki-laki) / pacar laki-laki', 'Kata ganti', 'Bisa berarti "dia" (lk) atau "pacar laki-laki"', '三人称の代名詞', 'Kata ganti orang ketiga untuk laki-laki. Dalam konteks tertentu juga berarti pacar.', '彼はやさしいです。', 'かれはやさしいです。', 'Dia (lk) baik hati.', 13),
(1, '彼女', 'かのじょ', 'kanojo', 'dia (perempuan) / pacar perempuan', 'Kata ganti', 'Bisa berarti "dia" (pr) atau "pacar perempuan"', '三人称の代名詞', 'Kata ganti orang ketiga untuk perempuan. Dalam konteks tertentu berarti pacar perempuan.', '彼女は先生です。', 'かのじょはせんせいです。', 'Dia (pr) adalah guru.', 14),
(1, '名前', 'なまえ', 'namae', 'nama', 'Kata benda', 'Kata umum untuk "nama" seseorang atau sesuatu', '人や物の呼び名', 'Nama orang, benda, atau tempat. Tambahkan お (お名前) untuk versi sopan.', 'お名前は何ですか。', 'おなまえはなんですか。', 'Siapa nama Anda?', 15),
(1, '学生', 'がくせい', 'gakusei', 'pelajar / mahasiswa', 'Kata benda', 'Umumnya pelajar tingkat universitas, juga bisa untuk pelajar pada umumnya', '学校で勉強する人', 'Pelajar atau mahasiswa. Untuk pelajar SD/SMP/SMA, lebih spesifik pakai 小学生/中学生/高校生.', '私は日本語の学生です。', 'わたしはにほんごのがくせいです。', 'Saya adalah pelajar bahasa Jepang.', 16),
(1, '先生', 'せんせい', 'sensei', 'guru / dokter', 'Kata benda', 'Sebutan hormat untuk guru, dokter, ahli, atau profesional', '教師、医者などの敬称', 'Gelar hormat. Selalu tambahkan setelah nama: 田中先生 (Pak Tanaka guru).', '田中先生は優しいです。', 'たなかせんせいはやさしいです。', 'Pak Tanaka (guru) baik hati.', 17),
(1, '友達', 'ともだち', 'tomodachi', 'teman', 'Kata benda', 'Teman biasa, tidak terikat usia', '親しい人', 'Kata umum untuk teman. Untuk sahabat dekat: 親友 (しんゆう).', '友達と映画を見ます。', 'ともだちとえいがをみます。', 'Menonton film bersama teman.', 18),
(1, '家族', 'かぞく', 'kazoku', 'keluarga', 'Kata benda', 'Anggota keluarga inti', '一緒に住む親しい人', 'Keluarga inti (orang tua, saudara). Untuk keluarga besar: 親戚 (しんせき).', '家族は四人です。', 'かぞくはよにんです。', 'Keluarga saya empat orang.', 19),
(1, '父', 'ちち', 'chichi', 'ayah (sendiri)', 'Kata benda', 'Ayah dari diri sendiri (saat bicara ke orang lain)', '自分の父親', 'Dipakai saat menyebut ayah sendiri ke orang lain. Untuk ayah orang lain: お父さん.', '父は会社員です。', 'ちちはかいしゃいんです。', 'Ayah saya adalah karyawan kantor.', 20),
(1, '母', 'はは', 'haha', 'ibu (sendiri)', 'Kata benda', 'Ibu dari diri sendiri (saat bicara ke orang lain)', '自分の母親', 'Dipakai saat menyebut ibu sendiri ke orang lain. Untuk ibu orang lain: お母さん.', '母は料理が上手です。', 'はははりょうりがじょうずです。', 'Ibu saya pandai memasak.', 21),
(1, '兄', 'あに', 'ani', 'kakak laki-laki (sendiri)', 'Kata benda', 'Kakak lk dari diri sendiri (saat bicara ke orang lain)', '自分の兄', 'Untuk kakak laki-laki sendiri. Untuk kakak orang lain: お兄さん.', '兄は東京に住んでいます。', 'あにはとうきょうにすんでいます。', 'Kakak laki-laki saya tinggal di Tokyo.', 22),
(1, '姉', 'あね', 'ane', 'kakak perempuan (sendiri)', 'Kata benda', 'Kakak pr dari diri sendiri (saat bicara ke orang lain)', '自分の姉', 'Untuk kakak perempuan sendiri. Untuk kakak orang lain: お姉さん.', '姉は看護師です。', 'あねはかんごしです。', 'Kakak perempuan saya adalah perawat.', 23),
(1, '弟', 'おとうと', 'otōto', 'adik laki-laki', 'Kata benda', 'Adik laki-laki', '年下の男の兄弟', 'Adik laki-laki. Sama untuk milik sendiri maupun orang lain.', '弟は高校生です。', 'おとうとはこうこうせいです。', 'Adik laki-laki saya pelajar SMA.', 24),
(1, '妹', 'いもうと', 'imōto', 'adik perempuan', 'Kata benda', 'Adik perempuan', '年下の女の兄弟', 'Adik perempuan. Sama untuk milik sendiri maupun orang lain.', '妹は元気です。', 'いもうとはげんきです。', 'Adik perempuan saya sehat.', 25),
(1, '人', 'ひと', 'hito', 'orang', 'Kata benda', 'Manusia atau orang secara umum', '人間', 'Kata umum untuk orang. Untuk hitungan orang: 一人 (ひとり), 二人 (ふたり).', 'あの人は誰ですか。', 'あのひとはだれですか。', 'Siapa orang itu?', 26),
(1, '男', 'おとこ', 'otoko', 'laki-laki / pria', 'Kata benda', 'Pria atau jenis kelamin laki-laki', '男性', 'Kata umum untuk laki-laki. Lebih sopan: 男性 (だんせい). Untuk anak laki-laki: 男の子.', 'あの男の人は背が高いです。', 'あのおとこのひとはせがたかいです。', 'Pria itu tinggi.', 27),
(1, '女', 'おんな', 'onna', 'perempuan / wanita', 'Kata benda', 'Wanita atau jenis kelamin perempuan', '女性', 'Kata umum untuk perempuan. Lebih sopan: 女性 (じょせい). Untuk anak perempuan: 女の子.', '女の子が公園で遊んでいます。', 'おんなのこがこうえんであそんでいます。', 'Anak perempuan bermain di taman.', 28),
(1, '子供', 'こども', 'kodomo', 'anak', 'Kata benda', 'Anak (anak-anak) atau anak dari seseorang', '小さい人', 'Bisa berarti anak-anak secara umum, atau anak dari orang tua.', '子供が三人います。', 'こどもがさんにんいます。', 'Saya punya tiga anak.', 29),
(1, '日本', 'にほん', 'nihon', 'Jepang', 'Kata benda', 'Nama negara Jepang', '日本国', 'Nama negara Jepang. Juga dibaca にっぽん (nippon) dalam konteks formal.', '日本は美しい国です。', 'にほんはうつくしいくにです。', 'Jepang adalah negara yang indah.', 30),
(1, '日本人', 'にほんじん', 'nihonjin', 'orang Jepang', 'Kata benda', 'Warga negara Jepang atau orang berkebangsaan Jepang', '日本国籍の人', 'Pola: nama negara + 人 (じん) = orang dari negara itu. Contoh: アメリカ人, インドネシア人.', '私の友達は日本人です。', 'わたしのともだちはにほんじんです。', 'Teman saya orang Jepang.', 31),
(1, '日本語', 'にほんご', 'nihongo', 'bahasa Jepang', 'Kata benda', 'Bahasa Jepang', '日本の言語', 'Pola: nama negara + 語 (ご) = bahasa negara itu. Contoh: 英語, 中国語, インドネシア語.', '日本語を勉強しています。', 'にほんごをべんきょうしています。', 'Saya sedang belajar bahasa Jepang.', 32),
(1, '英語', 'えいご', 'eigo', 'bahasa Inggris', 'Kata benda', 'Bahasa Inggris', '英国・米国の言語', 'Bahasa Inggris. Catatan: 英 berasal dari 英国 (Inggris).', '英語が話せますか。', 'えいごがはなせますか。', 'Bisakah Anda berbahasa Inggris?', 33),
(1, '学校', 'がっこう', 'gakkō', 'sekolah', 'Kata benda', 'Institusi pendidikan secara umum', '勉強する場所', 'Sekolah secara umum. Untuk universitas: 大学, SMA: 高校.', '毎日学校に行きます。', 'まいにちがっこうにいきます。', 'Setiap hari saya pergi ke sekolah.', 34),
(1, '大学', 'だいがく', 'daigaku', 'universitas', 'Kata benda', 'Universitas atau perguruan tinggi', '高等教育機関', 'Universitas. Mahasiswa universitas: 大学生 (だいがくせい).', '東京大学に通っています。', 'とうきょうだいがくにかよっています。', 'Saya kuliah di Universitas Tokyo.', 35),
(1, '会社', 'かいしゃ', 'kaisha', 'perusahaan / kantor', 'Kata benda', 'Perusahaan atau tempat kerja', '仕事をする組織', 'Perusahaan. Karyawan kantor: 会社員 (かいしゃいん).', '会社に行きます。', 'かいしゃにいきます。', 'Saya pergi ke kantor.', 36),
(1, '家', 'いえ', 'ie', 'rumah', 'Kata benda', 'Rumah sebagai bangunan atau tempat tinggal', '住む場所', 'Rumah. Bisa juga dibaca うち (uchi) yang lebih menekankan "rumah saya" sebagai keluarga.', '家に帰ります。', 'いえにかえります。', 'Saya pulang ke rumah.', 37),
(1, '部屋', 'へや', 'heya', 'kamar / ruangan', 'Kata benda', 'Ruangan di dalam bangunan', '建物の中の区切られた空間', 'Kamar atau ruangan. Contoh: 寝室 (kamar tidur), 居間 (ruang keluarga).', '私の部屋は狭いです。', 'わたしのへやはせまいです。', 'Kamar saya sempit.', 38),
(1, 'トイレ', 'トイレ', 'toire', 'toilet', 'Kata benda', 'Kamar mandi atau toilet', 'お手洗い', 'Toilet, kata pinjaman dari Inggris. Versi formal/sopan: お手洗い (おてあらい).', 'トイレはどこですか。', 'トイレはどこですか。', 'Toilet di mana?', 39),
(1, '駅', 'えき', 'eki', 'stasiun', 'Kata benda', 'Stasiun kereta', '電車の発着所', 'Stasiun kereta. Untuk stasiun bus: バス停 (バスてい).', '駅まで歩きます。', 'えきまであるきます。', 'Berjalan sampai stasiun.', 40),
(1, '電車', 'でんしゃ', 'densha', 'kereta', 'Kata benda', 'Kereta listrik (transportasi umum di kota)', '電気で走る列車', 'Kereta listrik kota. Untuk shinkansen: 新幹線, kereta antar kota: 列車.', '電車で行きます。', 'でんしゃでいきます。', 'Pergi naik kereta.', 41),
(1, 'バス', 'バス', 'basu', 'bus', 'Kata benda', 'Bus sebagai transportasi umum', '大型の乗合自動車', 'Bus. Halte bus: バス停 (バスてい).', 'バスを待っています。', 'バスをまっています。', 'Sedang menunggu bus.', 42),
(1, '車', 'くるま', 'kuruma', 'mobil', 'Kata benda', 'Mobil sebagai kendaraan pribadi', '自動車', 'Mobil. Versi formal: 自動車 (じどうしゃ). Mengemudi mobil: 車を運転する.', '車を運転します。', 'くるまをうんてんします。', 'Mengemudikan mobil.', 43),
(1, '自転車', 'じてんしゃ', 'jitensha', 'sepeda', 'Kata benda', 'Sepeda', '足で漕ぐ二輪車', 'Sepeda. Naik sepeda: 自転車に乗る (じてんしゃにのる).', '自転車で学校に行きます。', 'じてんしゃでがっこうにいきます。', 'Pergi ke sekolah naik sepeda.', 44),
(1, '飛行機', 'ひこうき', 'hikōki', 'pesawat terbang', 'Kata benda', 'Pesawat terbang', '空を飛ぶ乗り物', 'Pesawat. Bandara: 空港 (くうこう). Naik pesawat: 飛行機に乗る.', '飛行機で日本に行きます。', 'ひこうきでにほんにいきます。', 'Pergi ke Jepang naik pesawat.', 45),
(1, '食べる', 'たべる', 'taberu', 'makan', 'Kata kerja golongan 2 (Ichidan)', 'Aktivitas mengonsumsi makanan', '食事をする', 'Kata kerja Ichidan, konjugasi: 食べます (taberu→tabemasu), 食べた (lampau), 食べない (negatif).', 'ご飯を食べます。', 'ごはんをたべます。', 'Saya makan nasi.', 46),
(1, '飲む', 'のむ', 'nomu', 'minum', 'Kata kerja golongan 1 (Godan)', 'Aktivitas mengonsumsi cairan', '液体を口に入れる', 'Kata kerja Godan. Konjugasi: 飲みます, 飲んだ, 飲まない. Juga untuk minum obat: 薬を飲む.', '水を飲みます。', 'みずをのみます。', 'Saya minum air.', 47),
(1, '行く', 'いく', 'iku', 'pergi', 'Kata kerja golongan 1 (Godan)', 'Berpindah ke tempat lain (menjauh dari pembicara)', 'ある場所へ向かう', 'Kata kerja Godan, sedikit irregular. Konjugasi: 行きます, 行った (bukan 行いた), 行かない.', '学校に行きます。', 'がっこうにいきます。', 'Saya pergi ke sekolah.', 48),
(1, '来る', 'くる', 'kuru', 'datang', 'Kata kerja tidak beraturan', 'Berpindah mendekat ke pembicara', 'こちらへ移動する', 'Kata kerja irregular. Konjugasi: 来ます (きます), 来た (きた), 来ない (こない).', '友達が来ます。', 'ともだちがきます。', 'Teman akan datang.', 49),
(1, '見る', 'みる', 'miru', 'melihat / menonton', 'Kata kerja golongan 2 (Ichidan)', 'Melihat sesuatu secara aktif', '目で見る', 'Untuk melihat secara umum, menonton TV/film. Untuk melihat tanpa sengaja: 見える (みえる).', 'テレビを見ます。', 'テレビをみます。', 'Saya menonton TV.', 50),
(1, '聞く', 'きく', 'kiku', 'mendengar / bertanya', 'Kata kerja golongan 1 (Godan)', 'Mendengar suara atau bertanya kepada seseorang', '耳で音をとらえる / 質問する', 'Dua makna: mendengarkan (音楽を聞く) atau bertanya (先生に聞く).', '音楽を聞きます。', 'おんがくをききます。', 'Saya mendengarkan musik.', 51),
(1, '話す', 'はなす', 'hanasu', 'berbicara', 'Kata kerja golongan 1 (Godan)', 'Berbicara atau bercakap-cakap dengan seseorang', '言葉で伝える', 'Berbicara. Untuk percakapan: 会話 (かいわ). Berbicara bahasa tertentu: 日本語を話す.', '日本語を話します。', 'にほんごをはなします。', 'Saya berbicara bahasa Jepang.', 52),
(1, '読む', 'よむ', 'yomu', 'membaca', 'Kata kerja golongan 1 (Godan)', 'Membaca buku, koran, dll', '文字を見て理解する', 'Membaca. Konjugasi: 読みます, 読んだ, 読まない.', '本を読みます。', 'ほんをよみます。', 'Saya membaca buku.', 53),
(1, '書く', 'かく', 'kaku', 'menulis', 'Kata kerja golongan 1 (Godan)', 'Menulis huruf, kalimat, atau dokumen', '文字を記す', 'Menulis. Juga untuk menggambar (絵を描く — kanji beda tapi pelafalan sama).', '手紙を書きます。', 'てがみをかきます。', 'Saya menulis surat.', 54),
(1, '買う', 'かう', 'kau', 'membeli', 'Kata kerja golongan 1 (Godan)', 'Membeli barang dengan uang', 'お金を払って物を得る', 'Membeli. Belanja: 買い物 (かいもの). Toko: 店 (みせ).', '本を買います。', 'ほんをかいます。', 'Saya membeli buku.', 55),
(1, '売る', 'うる', 'uru', 'menjual', 'Kata kerja golongan 1 (Godan)', 'Menjual barang untuk mendapatkan uang', 'お金と引き換えに物を渡す', 'Menjual. Bentuk negatif penjual: 売り切れ (sold out).', 'この店は本を売っています。', 'このみせはほんをうっています。', 'Toko ini menjual buku.', 56),
(1, '起きる', 'おきる', 'okiru', 'bangun', 'Kata kerja golongan 2 (Ichidan)', 'Bangun dari tidur', '目を覚ます', 'Bangun dari tidur. Juga bisa berarti "terjadi" (事故が起きる — terjadi kecelakaan).', '毎朝六時に起きます。', 'まいあさろくじにおきます。', 'Saya bangun jam 6 setiap pagi.', 57),
(1, '寝る', 'ねる', 'neru', 'tidur', 'Kata kerja golongan 2 (Ichidan)', 'Tidur atau berbaring', '横になって休む', 'Tidur. Lebih netral daripada 眠る (ねむる) yang berarti "tertidur".', '十一時に寝ます。', 'じゅういちじにねます。', 'Saya tidur jam 11.', 58),
(1, '働く', 'はたらく', 'hataraku', 'bekerja', 'Kata kerja golongan 1 (Godan)', 'Bekerja, baik fisik maupun mental', '仕事をする', 'Bekerja secara umum. Pekerjaan: 仕事 (しごと). Karyawan: 働く人 atau 社員.', '会社で働きます。', 'かいしゃではたらきます。', 'Saya bekerja di perusahaan.', 59),
